<template>
  <div id="network-renderer" class="network-renderer"></div>
</template>
<script>
const THREE = require("three")
const OrbitControls = require('three-orbit-controls')(THREE)
const d3 = require("d3-force")
import _ from 'underscore';

export default {
  name: 'mnv-network-renderer',
  data() {
    return {
      v: {
        scene: null,
        globalLight: null,
        mainCamera: null,
        renderer: null,
        controls: null,
        world: null,
        raycaster: null,
        mousePosition: null,
        domRenderer: null,
        currentSelectedNode: null
      },
      physics: {
        nodes: [],
        links: []
      },
      renderedNetwork: {
        network: null,
        layers: [],
        nodes: [],
        edges: [],
        linkBuffer: []
      },
      index: {
        layerNodes: {},
        nodes: {}
      },
      /*network: {
        layers: [
          {
            id: 0,
            title: "Friends",
            color: "#ff0000"
          },
          {
            id: 1,
            title: "Enemies",
            color: "#ff00ff"
          },
          {
            id: 2,
            title: "Items",
            color: "#00ff00"
          },
          {
            id: 3,
            title: "Elements",
            color: "#00ffff"
          },
        ],
        nodes: [
          { id: 1, title: "Node 1" },
          { id: 2, title: "Node 2" },
          { id: 3, title: "Node 3" },
        ],
        links: [
          { source: 1, target: 4 },
          { source: 2, target: 5 },
          { source: 3, target: 6 },
          { source: 4, target: 1 },
          { source: 5, target: 2 },
          { source: 6, target: 3 },
          { source: 6, target: 2 },
          { source: 6, target: 1 },
          { source: 1, target: 5 },
          { source: 3, target: 1 },
          { source: 8, target: 5 }
        ],
        layerNodes: [
          {
            id: 1,
            title: "Node #1, layer 1",
            node: 1,
            layer: 1
          },
          {
            id: 2,
            title: "Node #1, layer 2",
            node: 1,
            layer: 2
          },
          {
            id: 3,
            title: "Node #1, layer 3",
            node: 1,
            layer: 2
          },
          {
            id: 4,
            title: "Node #2, layer 1",
            node: 2,
            layer: 1
          },
          {
            id: 5,
            title: "Node #2, layer 2",
            node: 2,
            layer: 2
          },
          {
            id: 6,
            title: "Node #2, layer 3",
            node: 2,
            layer: 3
          },
          {
            id: 7,
            title: "Node #3, layer 1",
            node: 3,
            layer: 1
          },
          {
            id: 8,
            title: "Node #3, layer 2",
            node: 3,
            layer: 2
          },
          {
            id: 9,
            title: "Node #3, layer 3",
            node: 3,
            layer: 3
          },
        ]
      }
      */
    };
  },
  watch: {
    // eslint-disable-next-line
    network: function (n) {
      // The network has changed, time to rebuild the
      this.instantiateNetwork();
    },

    sceneBackgroundColor: function (n) {
      this.v.scene.background = new THREE.Color(n);
    },

    lightColor: function (n) {
      this.v.globalLight.color = new THREE.Color(n);
    },

    lightIntensity: function (n) {
      this.v.globalLight.intensity = n;
    },

    layerDistance: _.debounce(function () {
      this.instantiateNetwork();
    }, 500)
  },
  props: {
    'network': {
      type: Object,
      default: function () {
        return {};
      }
    },
    'nodeSize': {
      type: Number,
      default: 5
    },
    'layerDistance': {
      type: Number,
      default: 50
    },
    'sceneBackgroundColor': {
      type: String,
      default: "#cccccc"
    },
    'lightIntensity': {
      type: Number,
      default: 20
    },
    'lightColor': {
      type: String,
      default: '#222222'
    }
  },
  methods: {
    /**
     * Called only once when starting the component to initialize
     * a few elements.
     */
    init: function () {
      // This is the dom element the view will be appended to:
      const domRenderer = document.getElementById("network-renderer");
      // We will disable the controls once the user is not inside it:
      domRenderer.addEventListener("mouseover", () => {
        this.v.controls.enabled = true;
      });
      domRenderer.addEventListener("mouseout", () => {
        this.v.controls.enabled = false;
      });
      domRenderer.addEventListener("mousemove", (event) => {
        event.preventDefault();
        const dom = this.v.renderer.domElement;
        this.v.mousePosition.x = ((event.offsetX) / (window.innerWidth)) * 2 - 1;
        this.v.mousePosition.y = -((event.offsetY - dom.offsetTop) / dom.height) * 2 + 1;
        this.raycasterChecker('MouseMove');
      });
      domRenderer.addEventListener("click", (event) => {
        const dom = this.v.renderer.domElement;
        this.v.mousePosition.x = ((event.offsetX) / (window.innerWidth)) * 2 - 1;
        this.v.mousePosition.y = -((event.offsetY - dom.offsetTop) / dom.height) * 2 + 1;
        this.raycasterChecker('MouseClick');
        console.log("attemping click")
      });
      this.v.domRenderer = domRenderer;

      // Setting up scene:
      this.v.renderer = new THREE.WebGLRenderer({ antialias: true });
      this.v.renderer.setSize(window.innerWidth, window.innerHeight - 90);
      this.v.scene = new THREE.Scene();

      // Create and configure a new camera:
      this.v.mainCamera = new THREE.PerspectiveCamera(40, window.innerWidth / window.innerHeight, 1, 10000);
      this.v.mainCamera.position.set(600, 600, 600);
      this.v.mainCamera.lookAt(new THREE.Vector3());
      this.v.controls = new OrbitControls(this.v.mainCamera);
      this.v.globalLight = new THREE.AmbientLight(this.lightColor, this.lightIntensity);
      this.v.raycaster = new THREE.Raycaster();
      this.v.mousePosition = new THREE.Vector2();

      // Setup background color and lighting:
      this.v.scene.background = new THREE.Color(this.sceneBackgroundColor);
      this.v.scene.add(this.v.globalLight);

      // Add the new element to the scene:
      const view = domRenderer;
      view.appendChild(this.v.renderer.domElement);

      // Start the animation loop -- should be called last:
      this.animate();
    },

    clearNetwork: function () {
      this.clearNetworkModel();

      // Let's clear the references in physics:
      this.physics.nodes = [];
      this.physics.links = [];
    },

    clearNetworkModel: function () {
      // Start by removing the element from the scene:
      this.v.scene.remove(this.renderedNetwork.network);

      // Let's clear the network:
      this.renderedNetwork.network = null;
      this.renderedNetwork.layers = [];
      this.renderedNetwork.nodes = [];
      this.renderedNetwork.edges = [];
      this.renderedNetwork.linkBuffer = [];

      // Index:
      this.index.layerNodes = {};
      this.index.nodes = {};
    },


    /**
     * Intantiates the loaded network.
     * This should be called after the scene is set. 
     * This function loads the network model and set the physics and update
     * functions.
     */
    instantiateNetwork: function () {
      // Start by cleaning the network if there is any:
      this.clearNetwork();

      // Instantiate network object:
      this.renderedNetwork.network = new THREE.Object3D();
      this.v.scene.add(this.renderedNetwork.network);

      // Render the network on the screen:
      this.renderNetwork();

      // We will setup the physics. First step to join all the layers
      // in the network into one. This new network is what will be submitted
      // to the physics engine it can consider all nodes in the network.
      this.setupPhysics();

      // We are ready to instantiate the simulation:
      const simulation = d3.forceSimulation(this.physics.nodes)
        .force("link", d3.forceLink(this.physics.links).id(d => d.id))
        .force("charge", d3.forceManyBody())
        .force("center", d3.forceCenter(0, 0));

      // physicsTick will be called when it's time to update the models:
      simulation.on("tick", this.physicsTick);
    },

    setupPhysics: function () {
      this.network.layerNodes.map(layerNode => {
        const node = this.index.nodes[layerNode.node];
        if (node == undefined) {
          const data = {
            node: { id: layerNode.node },
            layerNodes: [
              layerNode
            ]
          };
          this.physics.nodes.push(data.node);
          this.index.nodes[layerNode.node] = data;
        } else {
          const layerNodeList = node.layerNodes;
          layerNodeList.push(layerNode);
        }
      });

      // Joing network edges into links:
      this.network.links.map(link => {
        const sourceLayerNode = this.index.layerNodes[link.source].element;
        const targetLayerNode = this.index.layerNodes[link.target].element;
        this.physics.links.push({
          source: sourceLayerNode.node,
          target: targetLayerNode.node
        });
      });
    },

    /**
     * Executes when the physics engine wants to update the items.
     * Responsable for updating the models.
     */
    physicsTick: function () {
      let x1 = -100;
      let x2 = 1000;
      let y1 = -100;
      let y2 = 1000;

      // We will update the position of every node in the network:
      this.network.nodes.map(element => {
        const layerNodes = this.index.nodes[element.id].layerNodes;
        const physicalNode = this.index.nodes[element.id].node;

        // Updating the current node's layer-nodes
        layerNodes.map(layerNode => {
          const renderNode = this.index.layerNodes[layerNode.id].render;
          renderNode.position.x = physicalNode.x;
          renderNode.position.y = physicalNode.y;
        })

        // Calculating the bounding box for the nodes, important
        // to set the size of the layers later:
        if (physicalNode.x > x1) {
          x1 = physicalNode.x;
        }
        if (physicalNode.x < x2) {
          x2 = physicalNode.x;
        }
        if (physicalNode.y > y1) {
          y1 = physicalNode.y;
        }
        if (physicalNode.y < y2) {
          y2 = physicalNode.y;
        }
      });

      // Once the nodes are updated, we will update the layers size
      // to include all layers in the network:
      this.renderedNetwork.layers.map(layer => {
        layer.scale.x = (x1 > x2 * -1 ? x1 : x2 * -1) * 2 + 10;
        layer.scale.y = (y1 > y2 * -1 ? y1 : y2 * -1) * 2 + 10;
      });

      // With the nodes and layers updated, we need to update the edges/links
      // between them so it may point to the right (updated) positions:
      let index = 0;
      const vertices = this.renderedNetwork.edgeBuffer.geometry.attributes.position.array;
      this.renderedNetwork.edges.map(link => {
        const source = link.from;
        const target = link.target;
        vertices[index++] = source.position.x;
        vertices[index++] = source.position.y;
        vertices[index++] = source.position.z;
        vertices[index++] = target.position.x;
        vertices[index++] = target.position.y;
        vertices[index++] = target.position.z;
      });

      // Tell Threejs to update the view and recalculate de the bounding sphere:
      this.renderedNetwork.edgeBuffer.geometry.attributes.position.needsUpdate = true;
      this.renderedNetwork.edgeBuffer.geometry.computeBoundingSphere();
    },

    animate: function () {
      this.v.renderer.render(this.v.scene, this.v.mainCamera);

      requestAnimationFrame(this.animate);
    },

    raycasterChecker: function (type) {
      this.v.raycaster.setFromCamera(this.v.mousePosition, this.v.mainCamera);
      const intersects = this.v.raycaster.intersectObjects(this.v.scene.children, true);

      let needCleaning = this.v.currentSelectedNode !== null;
      if (intersects.length > 0) {
        for (const element of intersects) {
          if (element.object.objectType === 'layerNode') {
            // A layernode is in selection
            if (element.object !== this.v.currentSelectedNode)
              this.clearCurrentNode();

            this.selectCurrentNode(type, element.object);
            needCleaning = false;
            break;
          }
        }
      }

      // Clear the current selected node:
      if (needCleaning) {
        this.clearCurrentNode();
      }
    },

    selectCurrentNode(type, object) {
      this.v.currentSelectedNode = object;
      object.material.color = new THREE.Color(0x000000);
      this.v.domRenderer.style.cursor = 'pointer';
      console.log(object.node.node, this.index.nodes[object.node.node]);
      this.$emit(`node${type}`,
        {
          'layerNode': this.index.layerNodes[object.nodeId].element,
          'mesh': this.index.layerNodes[object.nodeId].render,
          'node': this.index.nodes[object.node.node]
        });
    },

    clearCurrentNode() {
      const cNode = this.v.currentSelectedNode;
      if (cNode !== null) {
        cNode.material.color = new THREE.Color(this.index.layerNodes[cNode.nodeId].element.color);
        this.v.currentSelectedNode = null;
        this.v.domRenderer.style.cursor = 'default';
      }
    },

    /**
     * Draws the network.
     */
    renderNetwork: function () {
      // We start by rendering the layers:
      let layerNumber = 0;
      const layerZPosition = {};
      this.network.layers.map((layer) => {
        const renderedLayer = this.generateLayer(layer);
        renderedLayer.position.z = layerNumber * this.layerDistance;//180
        layerZPosition[layer.id] = renderedLayer.position.z;
        this.renderedNetwork.layers.push(renderedLayer);
        this.renderedNetwork.network.add(renderedLayer);
        layerNumber++;
      });

      this.network.layerNodes.map(node => {
        const renderedNode = this.generateNode(node);
        this.renderedNetwork.nodes.push(renderedNode);
        this.renderedNetwork.network.add(renderedNode);
        this.index.layerNodes[node.id] = {
          element: node,
          render: renderedNode
        };
        renderedNode.position.z = layerZPosition[node.layer];
      });

      this.network.links.map(link => {
        const source = this.index.layerNodes[link.source].render;
        const target = this.index.layerNodes[link.target].render;

        this.renderedNetwork.edges.push(
          {
            from: source,
            target: target,
          });
        this.addEdge(source, target);
      });
      const edge = this.generateEdges();
      console.log("Edge: ", edge);
      this.renderedNetwork.edgeBuffer = edge;
      this.renderedNetwork.network.add(edge);
    },

    generateLayer: (layer) => {
      const mesh = new THREE.BoxGeometry(1, 1, 1);
      const material = new THREE.MeshStandardMaterial({ color: layer.color, transparent: true, opacity: 0.1, side: THREE.DoubleSide });
      return new THREE.Mesh(mesh, material);
    },

    refreshNodes: function () {
      this.network.nodes.map(node => {
        this.refreshNode(node.id);
      })
    },

    refreshNode: function (nodeId) {
      const nodeData = this.index.nodes[nodeId];
      if (nodeData !== undefined) {
        nodeData.layerNodes.map(layerNodeData => {
          const indexedLayerNode = this.index.layerNodes[layerNodeData.id];
          const render = indexedLayerNode.render;
          const element = indexedLayerNode.element;
          render.material.color.set(element.color);
          if (element.opacity !== undefined) {
            render.material.transparent = true;
            render.material.opacity = element.opacity;
          }
        });
      }
    },

    generateNode: function (node) {
      if (node.color === undefined) node.color = '#2F4F4F';
      const geometry = new THREE.SphereBufferGeometry(this.nodeSize);//13
      const material = new THREE.MeshStandardMaterial({
        transparent: true,
        side: THREE.DoubleSide,
        depthWrite: false,
        depthTest: false,
        color: node.color
      });
      console.log("Generating node with id: ", node.id);
      const mesh = new THREE.Mesh(geometry, material);
      mesh.nodeId = node.id;
      mesh.node = node;
      mesh.objectType = 'layerNode';
      return mesh;
    },

    addEdge: function (source, target) {
      this.renderedNetwork.linkBuffer.push(source.position.x)
      this.renderedNetwork.linkBuffer.push(source.position.y)
      this.renderedNetwork.linkBuffer.push(source.position.z)

      this.renderedNetwork.linkBuffer.push(target.position.x)
      this.renderedNetwork.linkBuffer.push(target.position.y)
      this.renderedNetwork.linkBuffer.push(target.position.z)
    },

    generateEdges: function () {
      const material = new THREE.LineBasicMaterial({ color: 0x080808, transparent: false, opacity: 1, linewidth: .01 });// 0xcccccc

      const bufferGeometry = new THREE.BufferGeometry();
      const fvertices = new Float32Array(this.renderedNetwork.linkBuffer);
      bufferGeometry.addAttribute('position', new THREE.BufferAttribute(fvertices, 3));
      const line = new THREE.LineSegments(bufferGeometry, material);

      return line;
    },

    resizeRenderer: function () {
      this.v.mainCamera.aspect = window.innerWidth / (window.innerHeight - 90);
      this.v.mainCamera.updateProjectionMatrix();
      this.v.renderer.setSize(window.innerWidth, window.innerHeight - 90);
    },

    centerOnNetwork() {
      const e = new THREE.Box3().setFromObject(this.renderedNetwork.network);
      let center = new THREE.Vector3(0, 0, 0);
      e.getCenter(center);
      const position = this.renderedNetwork.network.position;
      this.v.controls.target.set(position.x + center.x, position.y + center.y, position.z + center.z);
    }
  },
  mounted() {
    this.init();

    window.addEventListener('resize', this.resizeRenderer, false);
  }
}
</script>
<style scoped>
.network-renderer {
  width: 100%;
  height: 100%;
  margin: 0px;
  padding: 0px;
}
</style>
<style>
canvas {
  height: 100% !important;
}
</style>
